package com.evernorth.smartemp.controller; import com.evernorth.smartemp.dto.ProjectDto; import com.evernorth.smartemp.enums.*; import com.evernorth.smartemp.service.ProjectService; import jakarta.validation.Valid; import lombok.RequiredArgsConstructor; import org.springframework.data.domain.*; import org.springframework.http.*; import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/projects") @RequiredArgsConstructor public class ProjectController{private final ProjectService s;@GetMapping public ResponseEntity<Page<ProjectDto.Response>> search(@RequestParam(defaultValue="0")int page,@RequestParam(defaultValue="5")int size,@RequestParam(required=false)String search,@RequestParam(required=false)ProjectStatus status,@RequestParam(required=false)Priority priority){return ResponseEntity.ok(s.search(search,status,priority,PageRequest.of(page,size)));}@PostMapping public ResponseEntity<ProjectDto.Response> create(@Valid@RequestBody ProjectDto.Request r){return ResponseEntity.status(HttpStatus.CREATED).body(s.create(r));}@PutMapping("/{id}")public ResponseEntity<ProjectDto.Response> update(@PathVariable Long id,@Valid@RequestBody ProjectDto.Request r){return ResponseEntity.ok(s.update(id,r));}@DeleteMapping("/{id}")public ResponseEntity<Void> delete(@PathVariable Long id){s.delete(id);return ResponseEntity.noContent().build();}}
